package main

import (
	"embed"
	"fmt"
	"html/template"
	"time"

	"github.com/gin-contrib/cache"
	"github.com/gin-contrib/cache/persistence"
	"github.com/gin-gonic/gin"
)

//go:embed template.html
var tmplFS embed.FS

func main() {
	r := gin.Default()

	// Parse embedded template
	tmpl, err := template.ParseFS(tmplFS, "template.html")
	if err != nil {
		panic(err)
	}
	r.SetHTMLTemplate(tmpl)

	store := persistence.NewInMemoryStore(60 * time.Second)
	// Non-cached Page
	r.GET("/ping", func(c *gin.Context) {
		c.String(200, "pong "+fmt.Sprint(time.Now().Unix()))
	})

	// Cached Page
	r.GET("/cache_ping", cache.CachePage(store, time.Minute, func(c *gin.Context) {
		c.String(200, "pong "+fmt.Sprint(time.Now().Unix()))
	}))

	// HTML Page using embedded template
	r.GET("/html", cache.CachePage(store, time.Minute, func(c *gin.Context) {
		name := c.DefaultQuery("name", "guest")
		c.HTML(200, "template.html", gin.H{
			"title":     "Cached HTML Page",
			"values":    "Hello from embed (" + name + ")!",
			"timestamp": time.Now().Format(time.RFC3339),
		})
	}))

	// Listen and Server in 0.0.0.0:8080
	_ = r.Run(":8080")
}

package main

import (
	"fmt"
	"log"
	"net/http"
	"time"

	"github.com/gin-contrib/gzip"
	"github.com/gin-gonic/gin"
)

func main() {
	r := gin.Default()
	r.Use(
		func(c *gin.Context) {
			c.Writer.Header().Add("Vary", "Origin")
		},
		gzip.Gzip(
			gzip.DefaultCompression,
			gzip.WithExcludedPaths([]string{"/ping2"}),
		))

	r.GET("/ping", func(c *gin.Context) {
		c.String(http.StatusOK, "pong "+fmt.Sprint(time.Now().Unix()))
	})
	r.GET("/ping2", func(c *gin.Context) {
		c.String(http.StatusOK, "pong "+fmt.Sprint(time.Now().Unix()))
	})
	r.GET("/stream", func(c *gin.Context) {
		c.Header("Content-Type", "text/event-stream")
		c.Header("Connection", "keep-alive")
		for i := 0; i < 10; i++ {
			fmt.Fprintf(c.Writer, "id: %d\ndata: tick %d\n\n", i, time.Now().Unix())
			c.Writer.Flush()
			time.Sleep(1 * time.Second)
		}
	})

	// Listen and Server in 0.0.0.0:8080
	if err := r.Run(":8080"); err != nil {
		log.Fatal(err)
	}
}

